package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import org.apache.datasketches.common.SketchesArgumentException;
import org.apache.datasketches.common.Util;

/** Builder for heap {@link UpdateOmniSketch} and {@link OmniSketchUnion} instances. */
public final class OmniSketchBuilder {
	/** Default width is 2^12 cells per row. */
	public static final int DEFAULT_LG_WIDTH = 12;
	/** Default number of independent rows. */
	public static final int DEFAULT_NUM_ROWS = 4;
	/** Default number of identifier hashes retained per cell. */
	public static final int DEFAULT_NOMINAL_ENTRIES = 1024;
	/** Minimum allowed lgWidth. */
	public static final int MIN_LG_WIDTH = 1;
	/** Maximum allowed lgWidth. */
	public static final int MAX_LG_WIDTH = 30;
	/** Maximum number of independent rows. */
	public static final int MAX_NUM_ROWS = 64;

	private int lgWidth = DEFAULT_LG_WIDTH;
	private int numRows = DEFAULT_NUM_ROWS;
	private int nominalEntries = DEFAULT_NOMINAL_ENTRIES;
	private long seed = Util.DEFAULT_UPDATE_SEED;

	/** Sets lg(width), where width must be between 2 and 2^30. */
	public OmniSketchBuilder setLgWidth(final int lgWidth) {
		if (lgWidth < MIN_LG_WIDTH || lgWidth > MAX_LG_WIDTH) {
			throw new SketchesArgumentException("lgWidth must be between " + MIN_LG_WIDTH + " and " + MAX_LG_WIDTH);
		}
		this.lgWidth = lgWidth;
		return this;
	}

	/** Sets the row width. The width must be a power of two and at least 2. */
	public OmniSketchBuilder setWidth(final int width) {
		if (width < 2 || (width & (width - 1)) != 0) {
			throw new SketchesArgumentException("width must be a power of two and at least 2");
		}
		return setLgWidth(Integer.numberOfTrailingZeros(width));
	}

	/** Sets the number of independent rows. */
	public OmniSketchBuilder setNumRows(final int numRows) {
		if (numRows < 1 || numRows > MAX_NUM_ROWS) {
			throw new SketchesArgumentException("numRows must be between 1 and " + MAX_NUM_ROWS);
		}
		this.numRows = numRows;
		return this;
	}

	/** Sets the number of min-hash identifier entries retained by each cell. */
	public OmniSketchBuilder setNominalEntries(final int nominalEntries) {
		if (nominalEntries < 1) {
			throw new SketchesArgumentException("nominalEntries must be positive");
		}
		this.nominalEntries = nominalEntries;
		return this;
	}

	/** Sets the deterministic hash seed. */
	public OmniSketchBuilder setSeed(final long seed) {
		this.seed = seed;
		return this;
	}

	/** Returns lg(width). */
	public int getLgWidth() {
		return lgWidth;
	}

	/** Returns the row width. */
	public int getWidth() {
		return 1 << lgWidth;
	}

	/** Returns the configured number of rows. */
	public int getNumRows() {
		return numRows;
	}

	/** Returns the configured nominal entries per cell. */
	public int getNominalEntries() {
		return nominalEntries;
	}

	/** Returns the configured seed. */
	public long getSeed() {
		return seed;
	}

	/** Builds a heap update sketch. */
	public UpdateOmniSketch build() {
		return new UpdateOmniSketch(lgWidth, numRows, nominalEntries, seed);
	}

	/** Builds a heap union operation with this configuration. */
	public OmniSketchUnion buildUnion() {
		return new OmniSketchUnion(lgWidth, numRows, nominalEntries, seed);
	}
}
